class IndexedAllocation:
 def __init__(self, blockSize, numBlocks):
 self.blockSize = blockSize
 self.numBlocks = numBlocks
 self.indexBlock = [None] * numBlocks

 def allocate(self, fileSize):
 numBlocksNeeded = (fileSize + self.blockSize - 1) // self.blockSize
 if numBlocksNeeded <= self.numBlocks:
 startingBlock = 0
 while startingBlock < self.numBlocks and self.indexBlock[startingBlock] is not None:
 startingBlock += 1
 if startingBlock < self.numBlocks:
 for i in range(numBlocksNeeded):
 self.indexBlock[startingBlock + i] = i
 return startingBlock
 return -1

# Example usage
indexedAllocation = IndexedAllocation(512, 10)
startingBlock = indexedAllocation.allocate(1024)
if startingBlock != -1:
 print(f"Allocated {startingBlock}" )
else:
 print("Error allocating")

#include <stdio.h>

#define NUM_BLOCKS 10

unsigned char bitVector[NUM_BLOCKS / 8];

void setBit(int blockNumber) {
 int byteIndex = blockNumber / 8;
 int bitIndex = blockNumber % 8;
 bitVector[byteIndex] |= (1 << bitIndex);
}

void clearBit(int blockNumber) {
 int byteIndex = blockNumber / 8;
 int bitIndex = blockNumber % 8;
 bitVector[byteIndex] &= ~(1 << bitIndex);
}

int getBit(int blockNumber) {
 int byteIndex = blockNumber / 8;
 int bitIndex = blockNumber % 8;
 return (bitVector[byteIndex] & (1 << bitIndex)) != 0;
}

// Example usage
int main() {
 setBit(3);
 printf("Bit 3 is %d\n", getBit(3));
 clearBit(3);
 printf("Bit 3 is %d\n", getBit(3));
 return 0;
}
